 39→async function runEnable(): Promise<void> {
 40→	const write = (msg: string) => process.stdout.write(`${msg}\n`);
 41→	const writeError = (msg: string) => process.stderr.write(`${msg}\n`);
 42→
 43→	// Verify auth (loads credentials + pings API)
 44→	const auth = await verifyAuth();
 45→	if (!auth.authenticated) {
 46→		writeError(`Error: ${auth.message}`);
 47→		process.exitCode = 1;
 48→		return;
 49→	}
 50→
 51→	const { credentials } = auth;
 52→
 53→	// Fetch user's organizations
 54→	const client = createApiClient(credentials);
 55→	let orgs: { id: string; name: string; slug: string }[];
 56→	try {
 57→		orgs = await client.listMyOrganizations();
 58→	} catch {
 59→		writeError("Error: Failed to fetch organizations. Check your connection.");
 60→		process.exitCode = 1;
 61→		return;
 62→	}
 63→
 64→	if (orgs.length === 0) {
 65→		writeError(
 66→			"Error: No organizations found. Create one at app.rudel.ai first.",
 67→		);
 68→		process.exitCode = 1;
 69→		return;
 70→	}
 71→
 72→	// Check if already configured for this project
 73→	const cwd = process.cwd();
 74→	const existingOrgId = await getProjectOrgId(cwd);
 75→	const existingOrg = existingOrgId
 76→		? orgs.find((o) => o.id === existingOrgId)
 77→		: undefined;
 78→
 79→	let selectedOrgId: string;
 80→
 81→	const [firstOrg] = orgs;
 82→	if (orgs.length === 1 && firstOrg) {
 83→		selectedOrgId = firstOrg.id;
 84→		write(`Using organization: ${firstOrg.name}`);
 85→	} else if (existingOrg) {
 86→		write(`Currently configured for: ${existingOrg.name}`);
 87→		selectedOrgId = existingOrg.id;
 88→	} else {
 89→		write("Select an organization for this repository:");
 90→		for (const [i, org] of orgs.entries()) {
 91→			write(`  ${i + 1}. ${org.name} (${org.slug})`);
 92→		}
 93→		const choice = await promptChoice(
 94→			`Choice [1-${orgs.length}]: `,
 95→			orgs.length,
 96→		);
 97→		const selected = orgs[choice - 1] ?? orgs[0];
 98→		if (!selected) return;
 99→		selectedOrgId = selected.id;
100→		write(`Selected: ${selected.name}`);
101→	}
102→
103→	await setProjectOrgId(cwd, selectedOrgId);
104→
105→	// Install hook via agent abstraction
106→	const agent = getDefaultAgent();
107→
108→	if (agent.isHookInstalled()) {
109→		write("Auto-upload hook is already enabled. Organization updated.");
110→	} else {
111→		agent.installHook();
112→		write(`Auto-upload hook enabled in ${agent.getHookSettingsPath()}`);
113→	}
114→
115→	// Check for existing sessions to upload
116→	const sessions = await agent.findProjectSessions(cwd);
117→	if (sessions.length === 0) return;
118→
119→	const shouldUpload = await promptYesNo(
120→		`Found ${sessions.length} previous session(s). Upload them now? [y/N] `,
121→	);
122→	if (!shouldUpload) return;
123→
124→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
125→
126→	for (const [i, session] of sessions.entries()) {
127→		const label = `[${i + 1}/${sessions.length}]`;
128→		try {
129→			const content = await readTranscript(session.transcriptPath);
130→			const agentIds = extractAgentIds(content);
131→			const sessionDir = dirname(session.transcriptPath);
132→			const subagents =
133→				agentIds.length > 0
134→					? await readSubagentFiles(sessionDir, agentIds, session.sessionId)
135→					: [];
136→			const gitInfo = await getGitInfo(session.projectPath);
137→
138→			const request: IngestRequest = {
139→				sessionId: session.sessionId,
140→				projectPath: session.projectPath,
141→				repository: gitInfo.repository,
142→				gitBranch: gitInfo.branch,
143→				gitSha: gitInfo.sha,
144→				content,
145→				subagents: subagents.length > 0 ? subagents : undefined,
146→				organizationId: selectedOrgId,
147→			};
148→
149→			const result = await uploadSession(request, {
150→				endpoint,
151→				token: credentials.token,
152→			});
153→
154→			if (result.success) {
155→				write(`${label} Uploaded ${session.sessionId}`);
156→			} else {
157→				writeError(`${label} Failed ${session.sessionId}: ${result.error}`);
158→			}
159→		} catch (error) {
160→			writeError(
161→				`${label} Error ${session.sessionId}: ${error instanceof Error ? error.message : String(error)}`,
162→			);
163→		}
164→	}
165→}
