  1→import { resolve } from "node:path";
  2→
  3→const MONOREPO_ROOT = resolve(import.meta.dir, "..", "..", "..", "..", "..");
  4→
  5→export interface TestServer {
  6→	port: number;
  7→	baseUrl: string;
  8→	rpcUrl: string;
  9→	stop: () => Promise<void>;
 10→	/** Verify the server is still responding; restart it if Bun's test runner killed it. */
 11→	ensureAlive: () => Promise<void>;
 12→}
 13→
 14→/**
 15→ * Spawn the Bun API server with PORT=0 so the OS picks a free port.
 16→ * Migrations run automatically at startup.
 17→ */
 18→export async function startTestServer(): Promise<TestServer> {
 19→	const env = {
 20→		...process.env,
 21→		PORT: "0",
 22→		APP_URL: "http://localhost",
 23→		BETTER_AUTH_SECRET: "test-secret-for-integration-tests",
 24→		ALLOWED_ORIGIN: "http://localhost",
 25→	};
 26→
 27→	let proc = spawnServer(env);
 28→	let port = await parseReadyPort(proc);
 29→	drainStreams(proc);
 30→	await waitForReady(`http://localhost:${port}`);
 31→
 32→	const server: TestServer = {
 33→		get port() {
 34→			return port;
 35→		},
 36→		get baseUrl() {
 37→			return `http://localhost:${port}`;
 38→		},
 39→		get rpcUrl() {
 40→			return `http://localhost:${port}/rpc`;
 41→		},
 42→		async stop() {
 43→			proc.kill();
 44→			await proc.exited;
 45→		},
 46→		async ensureAlive() {
 47→			try {
 48→				const res = await fetch(`http://localhost:${port}/health`, {
 49→					signal: AbortSignal.timeout(2000),
 50→				});
 51→				if (res.ok) return;
 52→			} catch {
 53→				// Server is dead — restart it
 54→			}
 55→			proc = spawnServer(env);
 56→			port = await parseReadyPort(proc);
 57→			drainStreams(proc);
 58→			await waitForReady(`http://localhost:${port}`);
 59→		},
 60→	};
 61→
 62→	return server;
 63→}
 64→
 65→function spawnServer(env: Record<string, string | undefined>) {
 66→	const proc = Bun.spawn(["bun", "apps/api/src/index.ts"], {
 67→		cwd: MONOREPO_ROOT,
 68→		stdout: "pipe",
 69→		stderr: "pipe",
 70→		env,
 71→	});
 72→	proc.unref();
 73→	return proc;
 74→}
 75→
 76→function drainStreams(proc: ReturnType<typeof Bun.spawn>) {
 77→	if (proc.stdout instanceof ReadableStream) {
 78→		proc.stdout.pipeTo(new WritableStream()).catch(() => {});
 79→	}
 80→	if (proc.stderr instanceof ReadableStream) {
 81→		proc.stderr.pipeTo(new WritableStream()).catch(() => {});
 82→	}
 83→}
 84→
 85→/**
 86→ * Read stdout line-by-line until the server prints its "listening on" URL,
 87→ * then extract the port from it.
 88→ */
 89→async function parseReadyPort(
 90→	proc: ReturnType<typeof Bun.spawn>,
 91→): Promise<number> {
 92→	const stdout = proc.stdout;
 93→	if (!stdout || !(stdout instanceof ReadableStream)) {
 94→		throw new Error("Server process has no readable stdout");
 95→	}
 96→
 97→	const reader = stdout.getReader();
 98→	const decoder = new TextDecoder();
 99→	let buffer = "";
100→	const deadline = Date.now() + 30_000;
101→
102→	try {
103→		while (Date.now() < deadline) {
104→			const { value, done } = await reader.read();
105→			if (done) break;
106→			buffer += decoder.decode(value, { stream: true });
107→
108→			// index.ts prints: "API server listening on http://localhost:<port>"
109→			const match = buffer.match(/listening on https?:\/\/localhost:(\d+)/i);
110→			if (match?.[1]) {
111→				reader.releaseLock();
112→				return Number.parseInt(match[1], 10);
113→			}
114→		}
115→	} catch {
116→		// reader error — fall through to throw
117→	}
118→
119→	// If we get here we failed — grab stderr for diagnostics
120→	let stderrText = "";
121→	if (proc.stderr instanceof ReadableStream) {
122→		stderrText = await new Response(proc.stderr).text();
123→	}
124→
125→	proc.kill();
126→	throw new Error(
127→		`Server did not become ready within 30 s.\nstdout buffer: ${buffer}\nstderr: ${stderrText}`,
128→	);
129→}
130→
131→/**
132→ * Poll the server until it responds to a GET request.
133→ * Retries every 200ms for up to 10s.
134→ */
135→async function waitForReady(baseUrl: string): Promise<void> {
136→	const deadline = Date.now() + 10_000;
137→	while (Date.now() < deadline) {
138→		try {
139→			const res = await fetch(`${baseUrl}/health`, {
140→				signal: AbortSignal.timeout(2000),
141→			});
142→			if (res.ok) return;
143→		} catch {
144→			// Connection refused or timeout — retry
145→		}
146→		await Bun.sleep(200);
147→	}
148→	throw new Error(
149→		`Server at ${baseUrl} did not respond within 10s after port was detected`,
150→	);
151→}
152→
153→/**
154→ * Create a test user via better-auth sign-up and return a bearer token.
