+		expect(agent.getSessionsBaseDir()).toBe(SESSIONS_BASE);
+	});
+
+	test("findProjectSessions returns session files excluding subagents", async () => {
+		const sessions = await agent.findProjectSessions(TEST_PROJECT_PATH);
