	JSON.stringify({
		toolUseResult: { agentId: "sub-agent-001", result: "done" },
	}),
	JSON.stringify({
		toolUseResult: { agentId: "sub-agent-002", result: "done" },
	}),
].join("\n");

const SAMPLE_SUBAGENT_CONTENT = JSON.stringify({
	type: "message",
	role: "assistant",
